INSERT INTO RETENTION_PROCESS (
    STD_USER_ID, WDRW_RSN_CD, RTNP_CN, RTNP_RSLT_CD, CHRG_USER_ID, RTNP_DT, RGTR_ID
) VALUES (
    #{stdUserId}, #{wdrwRsnCd}, #{rtnpCn}, #{rtnpRsltCd}, #{chrgUserId},
    NVL(#{rtnpDt}, CURRENT_TIMESTAMP), #{rgtrId}
)

INSERT INTO STUDENT_ATTENDANCE (
    STD_USER_ID, ATND_TYPE_CD, ATND_REG_DT, ATND_NOTE_CN
) VALUES (
    #{stdUserId}, #{atndTypeCd}, #{atndRegDt}, #{atndNoteCn}
)
